import { Component, OnDestroy, OnInit } from "@angular/core";
import { Observable, BehaviorSubject, Subscription } from "rxjs";
import { map } from "rxjs/operators";
import {
  ClientWithLastInquiryInfo,
  IscoreHttpService,
} from "src/app/core/services/iscore-http.service";
import { SearchResult } from "../../Models/References/SearchResult";
import { HttpErrorResponse } from "@angular/common/http";
import { AlertService } from "src/app/core/services/alert.service";
import { Platform } from "@ionic/angular";
import { PdfViewerService } from "src/app/core/services/pdf-viewer.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { StaticRef } from "../../Models/References/StaticRef";

@Component({
  selector: "app-iscore-response",
  templateUrl: "./iscore-response.page.html",
  styleUrls: ["./iscore-response.page.scss"],
})
export class iscoreresponsePage implements OnInit, OnDestroy {
  private backButtonListener: Subscription;

  public showLoader: boolean = false;

  public inquirySuccess: boolean = false;

  private searchType = new BehaviorSubject<number>(1);
  public searchType$ = this.searchType.asObservable();

  private inquiryReason = new BehaviorSubject<number>(null);
  public inquiryReason$ = this.inquiryReason.asObservable();

  public sourcePage$: Observable<number> = this.searchType$.pipe(
    map((searchType) => (searchType == 1 ? 56 : 53))
  );

  public clientKey: string;

  public clientWithLastInquiryInfo: ClientWithLastInquiryInfo;
  public inquiryPdfBase64: string | null = null;

  inquiryReasonArray: StaticRef[] = [];

  constructor(
    private iscoreHttpService: IscoreHttpService,
    private alertService: AlertService,
    private platform: Platform,
    private pdfViewerService: PdfViewerService,
    private referencesService: ReferencesService
  ) {}

  async ngOnInit(): Promise<void> {
    this.backButtonListener = this.platform.backButton.subscribeWithPriority(
      10,
      (next) => {
        if (this.backButton()) {
          next();
        }
      }
    );
    this.inquiryReasonArray =
      await this.referencesService.getInquiryReasonIScore();
  }

  ngOnDestroy(): void {
    this.backButtonListener.unsubscribe();
  }

  backToSearch() {
    this.clientWithLastInquiryInfo = undefined;
    this.inquiryPdfBase64 = null;
    this.inquirySuccess = false;
    this.inquiryReason.next(null);
  }

  backButton(): boolean {
    if (!this.clientWithLastInquiryInfo) {
      return true;
    }
    this.backToSearch();
    return false;
  }

  public changeSearchType(searchType: number) {
    this.searchType.next(searchType);
  }

  public onClientSelected(client: SearchResult) {
    this.clientKey = client.client_key.toString();

    this.getClientWithLastInquiryInfo(this.clientKey);
  }

  public async getClientWithLastInquiryInfo(clientKey: string) {
    this.showLoader = true;
    try {
      this.clientWithLastInquiryInfo = await this.iscoreHttpService
        .getClientWithLastInquiryInfo(clientKey)
        .toPromise();
      this.showLoader = false;
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(JSON.stringify(err.error), false);
        return;
      }
    }
  }

  public onChangeInquiryReason(inquiryReason: number) {
    this.inquiryReason.next(inquiryReason);
  }

  public async inquire(clientKey: string) {
    const inquiryReason = this.inquiryReason.getValue();

    if (inquiryReason === null) {
      await this.alertService.showAlertError(
        "برجاء اختيار سبب الاستعلام",
        false
      );
      return;
    }

    const confirmation = await this.alertService.SaveAlert(
      "هل أنت متأكد من الاستعلام عن العميل؟"
    );

    if (!confirmation) {
      return;
    }

    try {
      this.showLoader = true;

      const inquiryResponse = await this.iscoreHttpService
        .inquire(clientKey, inquiryReason.toString())
        .toPromise();

      if (!inquiryResponse.success) {
        this.showLoader = false;
        this.alertService.showAlertError(inquiryResponse.error, false);
        return;
      }

      this.inquirySuccess = true;
      await this.getClientWithLastInquiryInfo(clientKey);

      this.showLoader = false;

      await this.alertService.popAlertBoolean(
        "هل ترغب في عرض مستند نتيجة الاستعلام؟",
        "تم الاستعلام",
        "inquiry-pdf-show-alert",
        [""],
        [
          {
            text: "عرض المستند",
            handler: () => {
              this.showInquiryPdf(inquiryResponse.inquiryId!);
            },
          },
          { text: "إلغاء", role: "cancel" },
        ]
      );
    } catch (err) {
      this.showLoader = false;
      if (err instanceof HttpErrorResponse) {
        this.alertService.showAlertError(JSON.stringify(err.error), false);
        return;
      }
    }
  }

  public async showInquiryPdf(inquiryId: number) {
    if (!this.pdfViewerService.canViewPdf()) {
      await this.alertService.showAlertError(
        "لا يمكن عرض أو تنزيل المستند على المتصفح الحالي",
        false
      );
      return;
    }

    await this.getInquiryPdf(inquiryId);

    await this.pdfViewerService.viewPdf(
      this.inquiryPdfBase64!,
      `inquiry_${inquiryId}.pdf`,
      "تقرير الاستعلام الائتماني"
    );
  }
  private async getInquiryPdf(inquiryId: number) {
    if (this.inquiryPdfBase64 == null) {
      this.showLoader = true;

      try {
        const pdfResponse = await this.iscoreHttpService
          .getInquiryPdf(inquiryId)
          .toPromise();

        this.inquiryPdfBase64 = pdfResponse.base64String;

        this.showLoader = false;
      } catch (err) {
        this.showLoader = false;
        if (err instanceof HttpErrorResponse) {
          this.alertService.showAlertError(JSON.stringify(err.error), false);
          return;
        }
      }
    }
  }
  isInquiryAvailable(): boolean {
    return (
      this.inquirySuccess ||
      (this.clientWithLastInquiryInfo.validInquiry &&
        this.clientWithLastInquiryInfo.applicationsWaitingInquiry == 0)
    );
  }
}
